package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        handleIncomingShare(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIncomingShare(intent)
    }

    private fun handleIncomingShare(intent: Intent) {
        if (intent.action == Intent.ACTION_SEND) {
            when (intent.type) {
                "text/plain" -> {
                    val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                    if (sharedText != null) {
                        processSharedText(sharedText)
                    }
                }
                "image/*" -> {
                    val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                    if (imageUri != null) {
                        processSharedImage(imageUri)
                    }
                }
            }
        }
    }

    private fun processSharedText(sharedText: String) {
        val textView: TextView = findViewById(R.id.shared_text_view)
        textView.text = sharedText
    }

    private fun processSharedImage(imageUri: Uri) {
        val imageView: ImageView = findViewById(R.id.shared_image_view)
        imageView.setImageURI(imageUri)
    }
